function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;
  if (typeof value !== "string") return fallback;
  try { return JSON.parse(value); } catch { return fallback; }
}

const payload = parseMaybeJson($json.payload, {});
return [{
  ...payload,
  notes: [
    ...(payload.notes || []),
    "subworkflowhandoff_humaninput_normalized"
  ]
}];

return [{
  ...$json,
  message_to_send: $json.execution_context.message || "Te voy a derivar con una persona para ayudarte mejor.",
  db_operations: ["handoff_cases", "messages", "lead_state"],
  handoff_case: {
    lead_id: $json.execution_context.lead_id,
    reason: $json.execution_context.handoff_reason || "handoff requested",
    summary:
      $json.execution_context.handoff_summary ||
      $json.context_packet?.conversation?.latest_user_message ||
      "Sin resumen",
    lead: $json.context_packet?.lead || {},
    state: $json.context_packet?.state || {},
    conversation: $json.context_packet?.conversation || {},
    metadata: {
      source_action: "handoff_human",
      idempotency_key: $json.execution_context?.idempotency_key || null
    }
  },
  state_update: {
    ...($json.execution_context.state_update || {}),
    stage: "human_handoff",
    human_handoff: true,
    next_goal: "human_takeover",
    last_bot_action: "handoff_human",
    missing_fields: []
  }
}];

function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;

  if (typeof value !== "string") return fallback;

  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

return [{
  lead_id: $json.lead_id || null,
  reason: $json.reason || "handoff_requested",
  summary: $json.summary || "Sin resumen",
  lead: parseMaybeJson($json.lead, {}),
  state: parseMaybeJson($json.state, {}),
  conversation: parseMaybeJson($json.conversation, {}),
  metadata: parseMaybeJson($json.metadata, {})
}];

const handoffCaseId =
  $json.handoff_case_id ||
  $json.handoff?.handoff_case_id ||
  null;

const assignedTo =
  $json.assigned_to ||
  $json.handoff?.assigned_to ||
  null;

const assignedTeam =
  $json.assigned_team ||
  $json.handoff?.assigned_team ||
  null;

const notificationSent =
  $json.notification_sent === true ||
  $json.handoff?.notification_sent === true;

const existingStateUpdate = $json.state_update || {};

return [
  {
    ...$json,

    handoff: true,
    handoff_case_id: handoffCaseId,
    assigned_to: assignedTo,
    assigned_team: assignedTeam,
    notification_sent: notificationSent,

    state_update: {
      ...existingStateUpdate,
      stage: "human_handoff",
      human_handoff: true,
      next_goal: "human_takeover",
      last_bot_action: "handoff_human",
      missing_fields: []
    },

    db_operations: [
      ...new Set([
        ...($json.db_operations || []),
        "handoff_cases",
        "messages",
        "lead_state"
      ])
    ],

    notes: [
      ...($json.notes || []),
      "handoff_case_created",
      notificationSent
        ? "handoff_notification_sent"
        : "handoff_notification_not_confirmed"
    ]
  }
];

